import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface EventData {
  event: string;
  date: string;
  venue: string;
  availability: string;
  ticketPrice: number;
}

interface EventWidgetData {
  upcomingEvents: EventData[];
}

export default function Widget() {
  const eventWidgetData = response.data as EventWidgetData;
  const events = eventWidgetData.upcomingEvents.slice(0, 3); // Only displaying up to 3 events

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#333', color: '#FFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#FFC107' }}>
            Upcoming Events
          </Typography>
          {events.map((event, index) => (
            <Box key={index} sx={{ bgcolor: '#444', p: 1, borderRadius: 1 }}>
              <Typography variant="body1" fontWeight={500}>
                {event.event}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Date: {new Date(event.date).toLocaleDateString()}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Venue: {event.venue}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Price: ${event.ticketPrice}
              </Typography>
              <Chip
                label={event.availability}
                sx={{ mt: 1, bgcolor: event.availability === 'Available' ? '#4CAF50' : event.availability === 'Limited' ? '#FF9800' : '#F44336', color: '#FFF' }}
              />
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
